UPDATE study_posts
   SET view_count = view_count + 1
 WHERE post_id = #{postId}

UPDATE study_posts
   SET category_id = #{categoryId}
     , title = #{title}
     , max_members = #{maxMembers}
     , content = #{content}
     , updated_at = SYSDATE
 WHERE post_id = #{postId}

UPDATE study_posts
   SET status = #{status}
     , updated_at = SYSDATE
 WHERE post_id = #{postId}
